SELECT z.ZONE_ID, z.PLANT_CD, z.WAREHOUSE_CD, z.ZONE_CD, z.ZONE_NM, z.ZONE_TYPE, z.SORT_SEQ, z.USE_YN, z.REG_USER_ID, z.REG_DTM, z.UPD_USER_ID, z.UPD_DTM, p.PLANT_NM, w.WAREHOUSE_NM, c.COM_NM AS ZONE_TYPE_NM FROM MCS_ZONE z INNER JOIN MST_PLANT p ON z.PLANT_CD = p.PLANT_CD INNER JOIN MST_WAREHOUSE w ON z.WAREHOUSE_CD = w.WAREHOUSE_CD LEFT JOIN COM_CODE c ON c.GRP_CD = 'MCS_ZONE_TYPE' AND z.ZONE_TYPE = c.COM_CD
AND z.PLANT_CD = #{plantCd} AND z.WAREHOUSE_CD = #{warehouseCd} AND z.ZONE_CD LIKE CONCAT('%', #{zoneCd}, '%') AND z.ZONE_NM LIKE CONCAT('%', #{zoneNm}, '%')
ORDER BY z.PLANT_CD, z.WAREHOUSE_CD, z.SORT_SEQ, z.ZONE_CD LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM MCS_ZONE z

    AND z.PLANT_CD = #{plantCd}
    AND z.WAREHOUSE_CD = #{warehouseCd}
    AND z.ZONE_CD LIKE CONCAT('%', #{zoneCd}, '%')
    AND z.ZONE_NM LIKE CONCAT('%', #{zoneNm}, '%')

